type Action = { type: 'ADD' } | { type: 'REMOVE' };

function reducer(action: Action) {
  switch (action.type) {
    case 'ADD':
      return 'adding';
    case 'REMOVE':
      return 'removing';
    default:
      // TypeScript will error here if a new Action type is added but not handled
      return assertNever(action);
  }
}

